import { GoogleGenAI } from "@google/genai";

const apiKey = process.env.API_KEY; // Assumed to be available
const ai = new GoogleGenAI({ apiKey: apiKey });

export const editImageWithGemini = async (
  base64Image: string,
  prompt: string
): Promise<string> => {
  if (!apiKey) {
    throw new Error("API Key not found");
  }

  try {
    // Remove header if present (e.g., "data:image/png;base64,")
    const cleanBase64 = base64Image.replace(/^data:image\/(png|jpeg|jpg|webp);base64,/, "");

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          {
            text: prompt,
          },
          {
            inlineData: {
              mimeType: 'image/png', // Assuming PNG for simplicity, can be dynamic
              data: cleanBase64,
            },
          },
        ],
      },
    });

    // Extract the generated image
    let generatedImage = "";
    if (response.candidates && response.candidates.length > 0) {
       for (const part of response.candidates[0].content.parts) {
         if (part.inlineData) {
           generatedImage = `data:image/png;base64,${part.inlineData.data}`;
           break;
         }
       }
    }

    if (!generatedImage) {
      throw new Error("No image generated by Gemini.");
    }

    return generatedImage;

  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

import React from 'react';
import { Flame } from 'lucide-react';

interface FlameButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  label: string;
  variant?: 'primary' | 'secondary' | 'danger';
  iconSize?: number;
}

export const FlameButton: React.FC<FlameButtonProps> = ({ 
  label, 
  variant = 'primary', 
  iconSize = 16,
  className = '',
  ...props 
}) => {
  let baseClasses = "flex items-center justify-center gap-2 rounded-full px-4 py-2 font-bold text-sm transition-transform active:scale-95 shadow-md";

  const variants = {
    primary: "bg-red-600 text-white hover:bg-red-700",
    secondary: "bg-gray-200 text-gray-800 hover:bg-gray-300",
    danger: "bg-black text-white hover:bg-gray-900 border border-red-500"
  };

  return (
    <button 
      className={`${baseClasses} ${variants[variant]} ${className}`}
      {...props}
    >
      <Flame size={iconSize} className="text-orange-500 fill-orange-500" />
      <span>{label}</span>
    </button>
  );
};

import React, { useState, useRef } from 'react';
import { FlameButton } from './FlameButton';
import { editImageWithGemini } from '../services/geminiService';
import { Loader2, Upload, Wand2, Download } from 'lucide-react';

export const GeminiStudio: React.FC = () => {
  const [selectedImage, setSelectedImage] = useState<string | null>(null);
  const [prompt, setPrompt] = useState('');
  const [generatedImage, setGeneratedImage] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setSelectedImage(reader.result as string);
        setGeneratedImage(null); // Reset previous result
      };
      reader.readAsDataURL(file);
    }
  };

  const handleGenerate = async () => {
    if (!selectedImage || !prompt) return;

    setIsLoading(true);
    setError(null);

    try {
      const result = await editImageWithGemini(selectedImage, prompt);
      setGeneratedImage(result);
    } catch (err) {
      setError("Failed to process image. Please try again.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="p-4 space-y-6 bg-white min-h-[80vh] rounded-t-3xl shadow-inner">
      <div className="text-center space-y-2">
        <h2 className="text-2xl font-suez text-brand-dark">Incendeia AI Studio</h2>
        <p className="text-sm text-gray-500">
          Powered by Gemini 2.5 Flash Image. Upload a photo and describe how to change it.
        </p>
      </div>

      {/* Input Area */}
      <div className="space-y-4">
        <div 
          onClick={() => fileInputRef.current?.click()}
          className="border-2 border-dashed border-gray-300 rounded-xl p-8 flex flex-col items-center justify-center cursor-pointer hover:bg-gray-50 transition-colors"
        >
            {selectedImage ? (
              <img 
                src={selectedImage} 
                alt="Original" 
                className="max-h-48 rounded-lg object-contain shadow-sm" 
              />
            ) : (
              <>
                <Upload className="text-gray-400 mb-2" size={32} />
                <span className="text-gray-500 text-sm font-semibold">Tap to upload photo</span>
              </>
            )}
            <input 
                type="file" 
                ref={fileInputRef}
                className="hidden" 
                accept="image/*"
                onChange={handleImageUpload}
            />
        </div>

        <div className="flex gap-2">
            <input 
                type="text"
                value={prompt}
                onChange={(e) => setPrompt(e.target.value)}
                placeholder="Ex: Add a retro filter, remove background..."
                className="flex-1 border border-gray-300 rounded-full px-4 py-2 focus:outline-none focus:border-red-500 text-sm"
            />
        </div>

        <div className="flex justify-center">
             <FlameButton 
                label={isLoading ? "Incendiando..." : "Transform Image"} 
                onClick={handleGenerate}
                disabled={!selectedImage || !prompt || isLoading}
                className={`w-full ${(!selectedImage || !prompt) ? 'opacity-50 cursor-not-allowed' : ''}`}
            />
        </div>
      </div>

      {/* Error Message */}
      {error && (
        <div className="bg-red-100 text-red-700 p-3 rounded-lg text-sm text-center">
            {error}
        </div>
      )}

      {/* Result Area */}
      {isLoading && (
        <div className="flex flex-col items-center justify-center py-8">
            <Loader2 className="animate-spin text-red-600 mb-2" size={40} />
            <span className="text-xs text-gray-500 animate-pulse">Gemini is painting...</span>
        </div>
      )}

      {generatedImage && !isLoading && (
        <div className="space-y-4 animate-fade-in border-t pt-4">
            <h3 className="font-suez text-center text-lg">Result</h3>
            <div className="relative rounded-xl overflow-hidden shadow-lg border-4 border-orange-500">
                <img src={generatedImage} alt="AI Generated" className="w-full h-auto" />
            </div>
            <a 
                href={generatedImage} 
                download="incendeia-ai.png"
                className="flex items-center justify-center gap-2 text-red-600 font-bold text-sm py-2 hover:bg-red-50 rounded-full"
            >
                <Download size={16} /> Save Image
            </a>
        </div>
      )}
    </div>
  );
};

