  content: string;
  image?: string;
  likes: number;
}

export enum UserRole {
  ADMIN = 'ADMIN',
  MEMBER = 'MEMBER',
  GUEST = 'GUEST'
}

export enum Language {
  PT = 'PT',
  ES = 'ES'
}

export interface User {
  id: string;
  nickname: string;
  role: UserRole;
  graduation: string;
  graduationColor: string;
  name?: string;
  since?: string; // Tempo de capoeira
  avatar?: string;
  mood?: string;
}

export enum NavSection {
  HOME = 'HOME',
  PROFILE = 'PROFILE',
  GALLERY = 'GALLERY',
  MASTERS = 'MASTERS',
  HISTORY = 'HISTORY',
  EVENTS = 'EVENTS',
  LOCATIONS = 'LOCATIONS',
  AI_STUDIO = 'AI_STUDIO',
  ADMIN_PANEL = 'ADMIN_PANEL',
  CHAT = 'CHAT',
  FORUM = 'FORUM',
  PARTNERS = 'PARTNERS',
  LIVE = 'LIVE',
  MEETING_ROOM = 'MEETING_ROOM',
  MEMBERS_WALL = 'MEMBERS_WALL'
}

// Data Models for the CMS
export interface Master {
  id: string;
  name: string;
  graduation: string;
  history: string;
  photo?: string;
}

export interface TrainingLocation {
  id: string;
  address: string;
  responsible: string;
  phone: string;
  mapLink: string;
}

export interface Event {
  id: string;
  title: string;
  date: string;
  location: string;
  poster?: string;
}

export interface GraduationSystem {
  id: string;
  name: string;
  color: string;
  meaning: string;
}

export interface ChatMessage {
  id: string;
  userId: string;
  nickname: string;
  text: string;
  timestamp: number;
  isAdmin: boolean;
}

export interface ForumPost {
  id: string;
  title: string;
  content: string;
  author: string;
  comments: { author: string; text: string }[];
}

import React, { useState, useRef, useEffect } from 'react';
import { User, UserRole, Language, NavSection, Master, TrainingLocation, Event, GraduationSystem, ChatMessage, ForumPost } from './types';
import { FlameButton } from './components/FlameButton';
import { GeminiStudio } from './components/GeminiStudio';
import { 
  Users, LogOut, ArrowLeft, Calendar, 
  MessageCircle, MapPin, Image as ImageIcon, BookOpen, Shield, Home, 
  Video, Globe, MessageSquare, PenTool, Trash2, Save, Plus, Camera, Map
} from 'lucide-react';

// --- INITIAL MOCK DATA ---
const INITIAL_MASTERS: Master[] = [
  { id: '1', name: 'Mestre Duende', graduation: 'Corda Vermelha', history: 'Fundador do grupo...', photo: null }
];
const INITIAL_LOCATIONS: TrainingLocation[] = [
  { id: '1', address: 'Centro Comunitário', responsible: 'Mestre Duende', phone: '551199999999', mapLink: '' }
];

// --- COMPONENTS ---

const Header = ({ title, onBack, onLogout }: { title: string, onBack?: () => void, onLogout: () => void }) => (
  <header className="bg-white shadow-sm sticky top-0 z-50 px-4 py-3 flex items-center justify-between border-b border-gray-100">
    <div className="flex items-center gap-2">
      {onBack && (
        <button onClick={onBack} className="p-2 rounded-full hover:bg-gray-100 text-brand-red">
          <ArrowLeft size={24} />
        </button>
      )}
      <h1 className="font-suez text-lg text-brand-dark tracking-wide truncate max-w-[200px]">{title}</h1>
    </div>
    <button onClick={onLogout} className="p-2 text-red-600 hover:bg-red-50 rounded-full flex flex-col items-center">
      <LogOut size={20} />
      <span className="text-[9px] font-bold">SAIR</span>
    </button>
  </header>
);

const SectionButton = ({ label, icon: Icon, onClick, colorClass }: any) => (
  <button
    onClick={onClick}
    className={`${colorClass} p-3 rounded-2xl shadow-md flex flex-col items-center justify-center gap-2 aspect-square transition-transform active:scale-95 border-b-4 border-black/10`}
  >
    <Icon size={28} />
    <span className="font-suez text-xs text-center leading-tight uppercase">{label}</span>
  </button>
);

const Footer = () => (
  <footer className="fixed bottom-0 w-full bg-white border-t border-gray-200 p-2 text-center z-40">
    <p className="text-[10px] text-gray-500 font-bold">APP INCENDEIA OFICIAL</p>
    <p className="text-[9px] text-gray-400">Desenvolvido por Mestre Duende</p>
  </footer>
);

// --- MAIN APP ---

export default function App() {
  // --- STATE ---
  const [user, setUser] = useState<User | null>(null);
  const [lang, setLang] = useState<Language>(Language.PT);
  const [currentSection, setCurrentSection] = useState<NavSection>(NavSection.HOME);
  const [loginMode, setLoginMode] = useState<'MEMBER' | 'ADMIN' | null>(null);

  // --- DATABASE STATE (Simulating Backend) ---
  const [masters, setMasters] = useState<Master[]>(INITIAL_MASTERS);
  const [locations, setLocations] = useState<TrainingLocation[]>(INITIAL_LOCATIONS);
  const [events, setEvents] = useState<Event[]>([]);
  const [graduations, setGraduations] = useState<GraduationSystem[]>([]);
  const [chatMessages, setChatMessages] = useState<ChatMessage[]>([]);
  const [forumPosts, setForumPosts] = useState<ForumPost[]>([]);
  const [members, setMembers] = useState<User[]>([]); // All registered users
  const [historyText, setHistoryText] = useState("A Capoeira é uma expressão cultural brasileira...");
  const [liveLink, setLiveLink] = useState("https://meet.google.com");

  // --- ADMIN STATE ---
  const [adminCount, setAdminCount] = useState(0);

  // --- ACTIONS ---

  const handleLogin = (role: UserRole, nickname: string, pass: string) => {
    if (!nickname || !pass) return alert("Preencha todos os campos!");

    if (role === UserRole.ADMIN) {
      if (adminCount >= 2) {
        // In a real app check if this specific user is one of the 2
        // For demo, we just warn if trying to register new
        // alert("Limite de Administradores atingido.");
      }
      setAdminCount(prev => prev + 1);
    }

    const newUser: User = {
      id: Date.now().toString(),
      nickname,
      name: nickname, // Default
      role,
      graduation: role === UserRole.MEMBER ? 'Iniciante' : 'Mestre',
      graduationColor: role === UserRole.MEMBER ? '#22c55e' : '#FFFFFF',
      since: '1 ano'
    };

    // Add to members list if not exists
    setMembers(prev => [...prev, newUser]);
    setUser(newUser);
    setCurrentSection(NavSection.HOME);
    setLoginMode(null);
  };

  const handleLogout = () => {
    setUser(null);
    setCurrentSection(NavSection.HOME);
    setLoginMode(null);
  };

  // --- RENDERERS ---

  // 1. LOGIN SCREEN
  if (!user) {
    return (
      <div className="min-h-screen bg-gray-50 flex flex-col items-center justify-center relative overflow-hidden p-4">
        {/* Language */}
        <div className="absolute top-10 flex gap-4 z-20 bg-white/50 p-2 rounded-full backdrop-blur-sm">
           <button onClick={() => setLang(Language.PT)} className={`opacity-${lang === Language.PT ? '100' : '40'} grayscale-${lang === Language.PT ? '0' : '100'} transition-all`}>
             <span className="text-3xl filter drop-shadow-md">🇧🇷</span>
           </button>
           <button onClick={() => setLang(Language.ES)} className={`opacity-${lang === Language.ES ? '100' : '40'} grayscale-${lang === Language.ES ? '0' : '100'} transition-all`}>
             <span className="text-3xl filter drop-shadow-md">🇪🇸</span>
           </button>
        </div>

        {/* LOGO */}
        <div className="mb-6 flex flex-col items-center z-10">
            <div className="w-40 h-40 bg-white rounded-full shadow-2xl flex items-center justify-center mb-6 border-4 border-orange-500 overflow-hidden relative">
               {/* Simulating Internal Storage Logo */}
               <div className="absolute inset-0 bg-gray-200 flex items-center justify-center">
                 <span className="text-center font-bold text-gray-400 text-xs">LOGO<br/>DO<br/>CLIENTE</span>
               </div>
            </div>

            {/* GRADIENT TITLE */}
            <h1 className="text-4xl font-suez text-center leading-none tracking-tight drop-shadow-sm">
              <span className="bg-gradient-to-r from-green-600 via-yellow-400 to-blue-600 text-transparent bg-clip-text block mb-1">
                INCENDEIA
              </span>
              <span className="bg-gradient-to-r from-red-600 via-yellow-400 text-transparent bg-clip-text block">
                CAPOEIRA
              </span>
            </h1>
        </div>

        {/* FORMS */}
        <div className="w-full max-w-xs space-y-4 z-10 mb-10">
          {!loginMode ? (
            <>
              <button 
                onClick={() => setLoginMode('MEMBER')}
                className="w-full bg-white border-2 border-green-100 p-4 rounded-3xl shadow-lg flex items-center justify-between hover:bg-green-50 transition-all active:scale-95"
              >
                <div className="flex items-center gap-3">
                  <div className="bg-green-500 p-3 rounded-full text-white"><Users size={24}/></div>
                  <div className="text-left">
                    <span className="block font-suez text-gray-800 text-lg">MEMBROS</span>
                    <span className="text-xs text-gray-500 font-bold">LOGIN / CADASTRO</span>
                  </div>
                </div>
              </button>

              <button 
                onClick={() => setLoginMode('ADMIN')}
                className="w-full bg-white border-2 border-red-100 p-4 rounded-3xl shadow-lg flex items-center justify-between hover:bg-red-50 transition-all active:scale-95"
              >
                <div className="flex items-center gap-3">
                  <div className="bg-red-600 p-3 rounded-full text-white"><Shield size={24}/></div>
                  <div className="text-left">
                    <span className="block font-suez text-gray-800 text-lg">ADM</span>
                    <span className="text-xs text-gray-500 font-bold">MESTRES (MAX 2)</span>
                  </div>
                </div>
              </button>
            </>
          ) : (
             <LoginForm 
                mode={loginMode} 
                onCancel={() => setLoginMode(null)} 
                onSubmit={(nick, pass) => handleLogin(loginMode === 'ADMIN' ? UserRole.ADMIN : UserRole.MEMBER, nick, pass)}
             />
          )}
        </div>

        <Footer />
      </div>
    );
  }

  // --- INTERNAL NAVIGATOR ---

  const renderContent = () => {
    // Shared Layout Wrapper
    const PageLayout = ({ title, children }: { title: string, children: React.ReactNode }) => (
       <div className="bg-gray-50 min-h-screen pb-20">
          <Header title={title} onLogout={handleLogout} onBack={() => setCurrentSection(NavSection.HOME)} />
          <div className="p-4 animate-fade-in">
            {children}
          </div>
       </div>
    );

    // 2. ADMIN PANEL
    if (currentSection === NavSection.ADMIN_PANEL) {
       return (
         <PageLayout title="PAINEL ADMINISTRATIVO">
            <div className="grid grid-cols-1 gap-4">
              <div className="bg-white p-4 rounded-2xl shadow-sm border border-gray-100">
                <h3 className="font-suez text-brand-dark mb-4 flex items-center gap-2"><PenTool size={16}/> EDITAR CONTEÚDO</h3>
                <div className="grid grid-cols-2 gap-3">
                   {/* CRUD Buttons for Admin */}
                   <AdminMenuButton label="Layout" icon={PenTool} onClick={() => alert("Editor de Layout: Fontes, Cores, Tema")} />
                   <AdminMenuButton label="Mestres" icon={Users} onClick={() => setCurrentSection(NavSection.MASTERS)} />
                   <AdminMenuButton label="Galeria" icon={ImageIcon} onClick={() => setCurrentSection(NavSection.GALLERY)} />
                   <AdminMenuButton label="Graduação" icon={Map} onClick={() => alert("Editor de Sistema de Graduação")} />
                   <AdminMenuButton label="Histórico" icon={BookOpen} onClick={() => setCurrentSection(NavSection.HISTORY)} />
                   <AdminMenuButton label="Locais" icon={MapPin} onClick={() => setCurrentSection(NavSection.LOCATIONS)} />
                   <AdminMenuButton label="Agenda" icon={Calendar} onClick={() => setCurrentSection(NavSection.EVENTS)} />
                   <AdminMenuButton label="Live Link" icon={Video} onClick={() => {
                      const newLink = prompt("Insira o novo link da Live (Zoom/Meet/WhatsApp):", liveLink);
                      if(newLink) setLiveLink(newLink);
                   }} />
                </div>
              </div>

              <div className="bg-red-50 p-4 rounded-2xl border-2 border-red-100">
                <h3 className="font-suez text-red-800 mb-2 flex items-center gap-2"><Shield size={16}/> SALA DE MESTRES</h3>
                <p className="text-xs text-red-600 mb-3">Área privada para reunião e debate entre os 2 ADMs.</p>
                <FlameButton label="ENTRAR NA SALA" variant="primary" className="w-full" onClick={() => setCurrentSection(NavSection.MEETING_ROOM)} />
              </div>
            </div>
         </PageLayout>
       );
    }

    // 3. MASTERS LIST (CRUD & VIEW)
    if (currentSection === NavSection.MASTERS) {
      return (
        <PageLayout title="MESTRES">
           {user.role === UserRole.ADMIN && (
             <div className="mb-4 bg-white p-4 rounded-xl shadow-sm">
                <h4 className="font-bold text-xs text-gray-500 mb-2 uppercase">Adicionar Mestre</h4>
                <div className="space-y-2">
                   <input id="masterName" type="text" placeholder="Nome" className="w-full border-b p-2 text-sm" />
                   <input id="masterGrad" type="text" placeholder="Graduação" className="w-full border-b p-2 text-sm" />
                   <div className="flex gap-2 pt-2">
                     <FlameButton label="SALVAR" onClick={() => {
                        const name = (document.getElementById('masterName') as HTMLInputElement).value;
                        const grad = (document.getElementById('masterGrad') as HTMLInputElement).value;
                        if(name) setMasters([...masters, { id: Date.now().toString(), name, graduation: grad, history: '' }]);
                     }} />
                   </div>
                </div>
             </div>
           )}
           <div className="space-y-3">
             {masters.map(m => (
               <div key={m.id} className="bg-white p-4 rounded-2xl shadow-sm flex items-center gap-4">
                  <div className="w-16 h-16 bg-gray-200 rounded-full flex-shrink-0"></div>
                  <div className="flex-1">
                    <h3 className="font-suez text-brand-dark">{m.name}</h3>
                    <p className="text-xs text-gray-500 font-bold">{m.graduation}</p>
                  </div>
                  {user.role === UserRole.ADMIN && (
                    <button onClick={() => setMasters(masters.filter(x => x.id !== m.id))} className="text-red-500"><Trash2 size={18}/></button>
                  )}
               </div>
             ))}
           </div>
        </PageLayout>
      );
    }

    // 4. LOCATIONS (CRUD & VIEW)
    if (currentSection === NavSection.LOCATIONS) {
      return (
        <PageLayout title="LOCAIS DE TREINO">
           {user.role === UserRole.ADMIN && (
             <div className="mb-4 bg-white p-4 rounded-xl shadow-sm">
                <h4 className="font-bold text-xs text-gray-500 mb-2 uppercase">Novo Local</h4>
                <input id="locAddr" type="text" placeholder="Endereço" className="w-full border-b p-2 text-sm mb-2" />
                <FlameButton label="ADICIONAR" onClick={() => {
                   const addr = (document.getElementById('locAddr') as HTMLInputElement).value;
                   if(addr) setLocations([...locations, { id: Date.now().toString(), address: addr, responsible: user.nickname, phone: '', mapLink: '' }]);
                }} />
             </div>
           )}
           <div className="space-y-4">
             {locations.map(l => (
               <div key={l.id} className="bg-white p-4 rounded-2xl shadow-sm">
                  <div className="flex justify-between items-start">
                    <div>
                      <h3 className="font-suez text-brand-dark text-sm">{l.address}</h3>
                      <p className="text-xs text-gray-500">Resp: {l.responsible}</p>
                    </div>
                    {user.role === UserRole.ADMIN && <button onClick={() => setLocations(locations.filter(x => x.id !== l.id))} className="text-red-500"><Trash2 size={16}/></button>}
                  </div>
                  <div className="mt-3 flex gap-2">
                     <button className="flex-1 bg-green-100 text-green-700 py-2 rounded-lg text-xs font-bold flex items-center justify-center gap-1"><Map size={14}/> MAPA</button>
                  </div>
               </div>
             ))}
           </div>
        </PageLayout>
      );
    }

    // 5. PROFILE
    if (currentSection === NavSection.PROFILE) {
      return (
        <PageLayout title="MEU PERFIL">
           <div className="bg-white rounded-3xl shadow-sm p-6 mb-4 flex flex-col items-center">
              {/* GRADUATION ANIMATION */}
              <div className="relative w-32 h-32 flex items-center justify-center mb-4">
                  <div className="absolute inset-0 rounded-full border-4 opacity-50 animate-ping" style={{ borderColor: user.graduationColor }}></div>
                  <div className="absolute inset-2 rounded-full border-4 opacity-70 animate-pulse" style={{ borderColor: user.graduationColor }}></div>
                  <div className="relative w-24 h-24 rounded-full bg-gray-100 border-4 shadow-xl flex items-center justify-center overflow-hidden" style={{ borderColor: user.graduationColor }}>
                     {user.avatar ? <img src={user.avatar} className="w-full h-full object-cover" /> : <Users size={40} className="text-gray-300" />}
                  </div>
              </div>

              <h2 className="font-suez text-2xl text-brand-dark mb-1">{user.nickname}</h2>
              <span className="px-3 py-1 bg-gray-100 rounded-full text-xs font-bold uppercase tracking-wider mb-6" style={{ color: user.graduationColor }}>
                {user.graduation}
              </span>

              {/* EDITABLE FIELDS */}
              <div className="w-full space-y-3">
                 <div>
                   <label className="text-[10px] font-bold text-gray-400 uppercase">Nome Completo</label>
                   <input type="text" defaultValue={user.name} className="w-full border-b border-gray-200 py-1 font-semibold text-gray-700" />
                 </div>
                 <div>
                   <label className="text-[10px] font-bold text-gray-400 uppercase">Tempo de Capoeira</label>
                   <input type="text" defaultValue={user.since} className="w-full border-b border-gray-200 py-1 font-semibold text-gray-700" />
                 </div>
                 <FlameButton label="SALVAR ALTERAÇÕES" className="w-full mt-4" />
              </div>
           </div>

           {/* INTERACTIVE */}
           <div className="grid grid-cols-2 gap-3 mb-4">
              <div className="bg-white p-4 rounded-2xl shadow-sm text-center">
                 <h4 className="font-suez text-sm mb-2">CHECK-IN</h4>
                 <FlameButton label="MARCAR" iconSize={12} className="w-full py-1 text-xs" />
              </div>
              <div className="bg-white p-4 rounded-2xl shadow-sm text-center">
                 <h4 className="font-suez text-sm mb-2">AGENDA</h4>
                 <FlameButton label="VER" iconSize={12} variant="secondary" className="w-full py-1 text-xs" />
              </div>
           </div>

           {/* MOOD TRACKER */}
           <div className="bg-white p-4 rounded-2xl shadow-sm">
             <h4 className="font-suez text-sm mb-3 text-center">COMO FOI O TREINO?</h4>
             <div className="flex justify-between px-2">
                {['🔥', '💪', '🤕', '🧘'].map(emoji => (
                  <button key={emoji} className="text-3xl hover:scale-125 transition-transform p-2">{emoji}</button>
                ))}
             </div>
           </div>
        </PageLayout>
      );
    }

    // 6. CHAT
    if (currentSection === NavSection.CHAT) {
      return (
         <PageLayout title="CHAT DA GALERA">
            <div className="bg-white rounded-2xl shadow-sm h-[60vh] flex flex-col overflow-hidden">
               <div className="flex-1 p-4 overflow-y-auto space-y-3 bg-gray-50">
                  {chatMessages.length === 0 && <p className="text-center text-gray-400 text-xs mt-10">Nenhuma mensagem ainda.</p>}
                  {chatMessages.map(msg => (
                    <div key={msg.id} className={`flex flex-col ${msg.userId === user.id ? 'items-end' : 'items-start'}`}>
                       <span className="text-[10px] text-gray-500 font-bold ml-1">{msg.nickname}</span>
                       <div className={`p-3 rounded-2xl max-w-[80%] text-sm ${msg.userId === user.id ? 'bg-orange-100 text-orange-900 rounded-tr-none' : 'bg-white border border-gray-200 rounded-tl-none'}`}>
                          {msg.text}
                       </div>
                    </div>
                  ))}
               </div>
               <div className="p-2 bg-white border-t flex gap-2">
                  <input id="chatInput" type="text" placeholder="Escreva..." className="flex-1 bg-gray-100 rounded-full px-4 text-sm focus:outline-none" />
                  <button 
                    onClick={() => {
                       const input = document.getElementById('chatInput') as HTMLInputElement;
                       if(input.value) {
                         setChatMessages([...chatMessages, { id: Date.now().toString(), userId: user.id, nickname: user.nickname, text: input.value, timestamp: Date.now(), isAdmin: user.role === UserRole.ADMIN }]);
                         input.value = '';
                       }
                    }}
                    className="bg-brand-red text-white p-3 rounded-full"
                  >
                     <MessageCircle size={18} />
                  </button>
               </div>
            </div>
         </PageLayout>
      );
    }

    // 7. MEMBERS WALL
    if (currentSection === NavSection.MEMBERS_WALL) {
      return (
        <PageLayout title="MURAL DOS INTEGRANTES">
           <div className="grid grid-cols-2 gap-3">
             {members.map((m, idx) => (
               <div key={idx} className="bg-white p-3 rounded-xl shadow-sm flex flex-col items-center text-center">
                  <div className="w-16 h-16 rounded-full bg-gray-100 mb-2 border-2" style={{ borderColor: m.graduationColor }}>
                     {m.avatar ? <img src={m.avatar} className="w-full h-full rounded-full" /> : <Users className="w-full h-full p-4 text-gray-300"/>}
                  </div>
                  <h4 className="font-suez text-sm text-brand-dark leading-none">{m.nickname}</h4>
                  <p className="text-[10px] text-gray-500 font-bold mt-1 uppercase" style={{color: m.graduationColor}}>{m.graduation}</p>
                  <p className="text-[9px] text-gray-400 mt-1">{m.since || 'Novo'}</p>
               </div>
             ))}
           </div>
        </PageLayout>
      );
    }

    // DEFAULT: HOME MENU (USER DASHBOARD)
    return (
      <div className="bg-gray-50 min-h-screen pb-20">
         <Header title="INCENDEIA" onLogout={handleLogout} />

         <div className="p-4 space-y-6 animate-fade-in">
            {/* WELCOME */}
            <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100">
               <h2 className="text-xl font-suez text-brand-dark mb-1">Olá, {user.nickname}!</h2>
               <div className="mt-4 bg-orange-50 p-4 rounded-xl border border-orange-100 relative overflow-hidden">
                  <div className="absolute right-[-10px] top-[-10px] text-orange-100 transform rotate-12"><MessageSquare size={60} /></div>
                  <h3 className="font-bold text-orange-800 text-xs uppercase mb-1 relative z-10">Aviso do Mestre</h3>
                  <p className="text-sm text-orange-700 italic relative z-10">"A capoeira é para todos, mas nem todos são para a capoeira. Treinem hoje às 19h!"</p>
               </div>
            </div>

            {/* DASHBOARD GRID */}
            <div className="grid grid-cols-2 gap-4">
               {/* Only visible to Admin */}
               {user.role === UserRole.ADMIN && (
                 <SectionButton label="PAINEL ADM" icon={Shield} colorClass="bg-gray-800 text-white" onClick={() => setCurrentSection(NavSection.ADMIN_PANEL)} />
               )}

               <SectionButton label="MEU PERFIL" icon={Users} colorClass="bg-blue-100 text-blue-600" onClick={() => setCurrentSection(NavSection.PROFILE)} />
               <SectionButton label="MURAL" icon={Globe} colorClass="bg-indigo-100 text-indigo-600" onClick={() => setCurrentSection(NavSection.MEMBERS_WALL)} />
               <SectionButton label="GALERIA" icon={ImageIcon} colorClass="bg-purple-100 text-purple-600" onClick={() => setCurrentSection(NavSection.GALLERY)} />
               <SectionButton label="HISTÓRIA" icon={BookOpen} colorClass="bg-amber-100 text-amber-700" onClick={() => setCurrentSection(NavSection.HISTORY)} />
               <SectionButton label="TREINOS" icon={MapPin} colorClass="bg-green-100 text-green-700" onClick={() => setCurrentSection(NavSection.LOCATIONS)} />
               <SectionButton label="AGENDA" icon={Calendar} colorClass="bg-red-100 text-red-600" onClick={() => setCurrentSection(NavSection.EVENTS)} />
               <SectionButton label="CHAT" icon={MessageCircle} colorClass="bg-teal-100 text-teal-600" onClick={() => setCurrentSection(NavSection.CHAT)} />
               <SectionButton label="LIVE" icon={Video} colorClass="bg-pink-100 text-pink-600" onClick={() => window.open(liveLink, '_blank')} />
               <SectionButton label="AI STUDIO" icon={Camera} colorClass="bg-gradient-to-br from-orange-400 to-red-500 text-white" onClick={() => setCurrentSection(NavSection.AI_STUDIO)} />
            </div>
         </div>
         <Footer />
      </div>
    );
  };

  return (
    <div className="min-h-screen font-sans bg-gray-50">
      <div className="max-w-md mx-auto bg-white min-h-screen shadow-2xl relative">
        {renderContent()}
      </div>
    </div>
  );
}

