  const handleLogin = (role: UserRole, nickname: string, pass: string) => {
    if (!nickname || !pass) return alert("Preencha todos os campos!");

    if (role === UserRole.ADMIN) {
      if (adminCount >= 2) {
        // In a real app check if this specific user is one of the 2
        // For demo, we just warn if trying to register new
        // alert("Limite de Administradores atingido.");
      }
      setAdminCount(prev => prev + 1);
    }

    const newUser: User = {
      id: Date.now().toString(),
      nickname,
      name: nickname, // Default
      role,
      graduation: role === UserRole.MEMBER ? 'Iniciante' : 'Mestre',
      graduationColor: role === UserRole.MEMBER ? '#22c55e' : '#FFFFFF',
      since: '1 ano'
    };

    // Add to members list if not exists
    setMembers(prev => [...prev, newUser]);
    setUser(newUser);
    setCurrentSection(NavSection.HOME);
    setLoginMode(null);
  };

  const handleLogout = () => {
    setUser(null);
    setCurrentSection(NavSection.HOME);
    setLoginMode(null);
  };

  const goHome = () => setCurrentSection(NavSection.HOME);

  // --- RENDERERS ---

  // 1. LOGIN SCREEN
  if (!user) {
    return (
      <div className="min-h-screen bg-gray-50 flex flex-col items-center justify-center relative overflow-hidden p-4">
        {/* Language */}
        <div className="absolute top-10 flex gap-4 z-20 bg-white/50 p-2 rounded-full backdrop-blur-sm">
           <button onClick={() => setLang(Language.PT)} className={`opacity-${lang === Language.PT ? '100' : '40'} grayscale-${lang === Language.PT ? '0' : '100'} transition-all`}>
             <span className="text-3xl filter drop-shadow-md">🇧🇷</span>
           </button>
           <button onClick={() => setLang(Language.ES)} className={`opacity-${lang === Language.ES ? '100' : '40'} grayscale-${lang === Language.ES ? '0' : '100'} transition-all`}>
             <span className="text-3xl filter drop-shadow-md">🇪🇸</span>
           </button>
        </div>

        {/* LOGO */}
        <div className="mb-6 flex flex-col items-center z-10">
            <div className="w-40 h-40 bg-white rounded-full shadow-2xl flex items-center justify-center mb-6 border-4 border-orange-500 overflow-hidden relative">
               {/* Simulating Internal Storage Logo */}
               <div className="absolute inset-0 bg-gray-200 flex items-center justify-center">
                 <span className="text-center font-bold text-gray-400 text-xs">LOGO<br/>DO<br/>CLIENTE</span>
               </div>
            </div>

            {/* GRADIENT TITLE */}
            <h1 className="text-4xl font-suez text-center leading-none tracking-tight drop-shadow-sm">
              <span className="bg-gradient-to-r from-green-600 via-yellow-400 to-blue-600 text-transparent bg-clip-text block mb-1">
                INCENDEIA
              </span>
              <span className="bg-gradient-to-r from-red-600 via-yellow-400 text-transparent bg-clip-text block">
                CAPOEIRA
              </span>
            </h1>
        </div>

        {/* FORMS */}
        <div className="w-full max-w-xs space-y-4 z-10 mb-10">
          {!loginMode ? (
            <>
              <button 
                onClick={() => setLoginMode('MEMBER')}
                className="w-full bg-white border-2 border-green-100 p-4 rounded-3xl shadow-lg flex items-center justify-between hover:bg-green-50 transition-all active:scale-95"
              >
                <div className="flex items-center gap-3">
                  <div className="bg-green-500 p-3 rounded-full text-white"><Users size={24}/></div>
                  <div className="text-left">
                    <span className="block font-suez text-gray-800 text-lg">MEMBROS</span>
                    <span className="text-xs text-gray-500 font-bold">LOGIN / CADASTRO</span>
                  </div>
                </div>
              </button>

              <button 
                onClick={() => setLoginMode('ADMIN')}
                className="w-full bg-white border-2 border-red-100 p-4 rounded-3xl shadow-lg flex items-center justify-between hover:bg-red-50 transition-all active:scale-95"
              >
                <div className="flex items-center gap-3">
                  <div className="bg-red-600 p-3 rounded-full text-white"><Shield size={24}/></div>
                  <div className="text-left">
                    <span className="block font-suez text-gray-800 text-lg">ADM</span>
                    <span className="text-xs text-gray-500 font-bold">MESTRES (MAX 2)</span>
