              </div>
            </div>
         </PageLayout>
       );
    }

    // 3. MASTERS LIST (CRUD & VIEW)
    if (currentSection === NavSection.MASTERS) {
      return (
        <PageLayout title="MESTRES" onBack={goHome} onLogout={handleLogout}>
