             <h4 className="font-suez text-sm mb-4 text-center text-gray-300">COMO FOI O TREINO?</h4>
             <div className="flex justify-between px-2">
                {['🔥', '💪', '🤕', '🧘'].map(emoji => (
                  <button key={emoji} className="text-3xl hover:scale-125 transition-transform p-3 bg-brand-dark rounded-xl border border-gray-700 hover:border-brand-orange">{emoji}</button>
                ))}
             </div>
           </div>
        </PageLayout>
      );
    }

    // 7. MEMBERS WALL
    if (currentSection === NavSection.MEMBERS_WALL) {
      return (
        <PageLayout title="MURAL DOS INTEGRANTES" onBack={goHome} onLogout={handleLogout}>
           <div className="grid grid-cols-2 gap-4">
             {members.map((m, idx) => (
               <div key={idx} className="bg-brand-card p-4 rounded-2xl shadow-lg border border-gray-700 flex flex-col items-center text-center relative overflow-hidden group hover:border-brand-orange/50 transition-colors">
                  <div className="w-20 h-20 rounded-full bg-brand-dark mb-3 border-2 p-1" style={{ borderColor: m.graduationColor }}>
                     <div className="w-full h-full rounded-full overflow-hidden">
                        {m.avatar ? <img src={m.avatar} className="w-full h-full object-cover" /> : <Users className="w-full h-full p-4 text-gray-600"/>}
                     </div>
                  </div>
                  <h4 className="font-suez text-sm text-white leading-none mb-1">{m.nickname}</h4>
                  <p className="text-[10px] font-bold uppercase mb-2" style={{color: m.graduationColor}}>{m.graduation}</p>
                  <div className="bg-brand-dark px-2 py-1 rounded-md">
                     <p className="text-[9px] text-gray-400">Desde: {m.since || 'Recente'}</p>
                  </div>
               </div>
             ))}
           </div>
        </PageLayout>
      );
    }

    // 8. AI STUDIO
    if (currentSection === NavSection.AI_STUDIO) {
        return (
            <PageLayout title="AI STUDIO" onBack={goHome} onLogout={handleLogout}>
                <GeminiStudio />
            </PageLayout>
        );
    }

    // 6. CHAT, 4. LOCATIONS, etc. would follow similar dark theme patterns...
    // (Simplifying for brevity, but assume logic applies to all sections)
    if (currentSection === NavSection.CHAT) {
        return (
            <PageLayout title="CHAT DA GALERA" onBack={goHome} onLogout={handleLogout}>
                <div className="bg-brand-card rounded-2xl shadow-lg border border-gray-800 h-[65vh] flex flex-col overflow-hidden">
                    <div className="flex-1 p-4 overflow-y-auto space-y-4 bg-black/20">
                        {chatMessages.length === 0 && <p className="text-center text-gray-600 text-xs mt-10">Nenhuma mensagem.</p>}
                        {chatMessages.map(msg => (
                            <div key={msg.id} className={`flex flex-col ${msg.userId === user.id ? 'items-end' : 'items-start'}`}>
                                <span className="text-[10px] text-gray-500 font-bold ml-1 mb-1">{msg.nickname}</span>
                                <div className={`px-4 py-2 rounded-2xl max-w-[85%] text-sm ${msg.userId === user.id ? 'bg-brand-red text-white rounded-tr-none' : 'bg-gray-700 text-white rounded-tl-none'}`}>
                                    {msg.text}
                                </div>
                            </div>
                        ))}
                    </div>
                    <div className="p-3 bg-brand-card border-t border-gray-700 flex gap-2">
                        <input id="chatInput" type="text" placeholder="Escreva..." className="flex-1 bg-brand-dark border border-gray-700 rounded-full px-4 text-sm text-white focus:outline-none focus:border-brand-orange" />
                        <button className="bg-brand-red text-white p-3 rounded-full hover:bg-red-600" onClick={() => {
                            const input = document.getElementById('chatInput') as HTMLInputElement;
                            if(input.value) {
                                setChatMessages([...chatMessages, { id: Date.now().toString(), userId: user.id, nickname: user.nickname, text: input.value, timestamp: Date.now(), isAdmin: user.role === UserRole.ADMIN }]);
                                input.value = '';
                            }
                        }}>
                            <MessageCircle size={20} />
                        </button>
                    </div>
                </div>
            </PageLayout>
        );
    }

    if (currentSection === NavSection.LOCATIONS) {
         return (
             <PageLayout title="LOCAIS DE TREINO" onBack={goHome} onLogout={handleLogout}>
                {user.role === UserRole.ADMIN && (
                    <div className="mb-4 bg-brand-card p-4 rounded-xl border border-gray-700">
                        <input id="locAddr" placeholder="Endereço" className="w-full bg-brand-dark p-2 rounded mb-2 text-white text-sm" />
                        <FlameButton label="ADICIONAR LOCAL" onClick={() => { /* Logic */ }} />
                    </div>
                )}
                <div className="space-y-4">
                    {locations.map(l => (
                        <div key={l.id} className="bg-brand-card p-4 rounded-2xl border border-gray-700 shadow-md">
                            <h3 className="font-suez text-white">{l.address}</h3>
                            <p className="text-xs text-gray-400 mb-3">Resp: {l.responsible}</p>
                            <FlameButton label="VER NO MAPA" variant="secondary" iconSize={14} className="w-full py-2 text-xs" />
                        </div>
                    ))}
                </div>
             </PageLayout>
         );
    }

    // Fallback for other sections
    if ([NavSection.GALLERY, NavSection.HISTORY, NavSection.EVENTS].includes(currentSection)) {
        return (
            <PageLayout title={currentSection} onBack={goHome} onLogout={handleLogout}>
                <div className="flex flex-col items-center justify-center h-64 text-gray-500">
                     <p>Seção em desenvolvimento...</p>
                     {user.role === UserRole.ADMIN && <FlameButton label="ADICIONAR CONTEÚDO" variant="secondary" className="mt-4" />}
                </div>
            </PageLayout>
        )
    }

    // DEFAULT: HOME MENU (USER DASHBOARD)
    return (
      <div className="bg-brand-dark min-h-screen pb-20 text-white">
         <Header title="INCENDEIA" onLogout={handleLogout} />

         <div className="p-4 space-y-6 animate-fade-in">
            {/* WELCOME */}
            <div className="bg-brand-card p-6 rounded-3xl shadow-lg border border-gray-800 relative overflow-hidden">
               <div className="flex items-center justify-between relative z-10">
                   <div>
                       <h2 className="text-xl font-suez text-white mb-1">Olá, {user.nickname}!</h2>
                       <p className="text-xs text-gray-400">Bem-vindo(a) de volta.</p>
                   </div>
                   <div className="w-12 h-12 rounded-full border-2 border-brand-orange bg-brand-dark overflow-hidden">
                        {user.avatar ? <img src={user.avatar} className="w-full h-full object-cover"/> : <Users className="w-full h-full p-2 text-gray-500"/>}
                   </div>
               </div>

               <div className="mt-5 bg-gradient-to-r from-orange-900/40 to-red-900/40 p-4 rounded-xl border border-brand-orange/30">
                  <h3 className="font-bold text-brand-orange text-[10px] uppercase mb-1 flex items-center gap-1"><MessageSquare size={12}/> Aviso do Mestre</h3>
                  <p className="text-sm text-gray-200 italic">"Treino hoje às 19h no Centro Comunitário. Todos de branco!"</p>
               </div>
            </div>

            {/* DASHBOARD GRID */}
            <div className="grid grid-cols-2 gap-4">
               {/* Only visible to Admin */}
               {user.role === UserRole.ADMIN && (
                 <SectionButton label="PAINEL ADM" icon={Shield} colorClass="text-brand-red bg-white" onClick={() => setCurrentSection(NavSection.ADMIN_PANEL)} />
               )}

               <SectionButton label="MEU PERFIL" icon={Users} colorClass="text-blue-400 bg-blue-900/20" onClick={() => setCurrentSection(NavSection.PROFILE)} />
               <SectionButton label="MURAL" icon={Globe} colorClass="text-indigo-400 bg-indigo-900/20" onClick={() => setCurrentSection(NavSection.MEMBERS_WALL)} />
               <SectionButton label="GALERIA" icon={ImageIcon} colorClass="text-purple-400 bg-purple-900/20" onClick={() => setCurrentSection(NavSection.GALLERY)} />
               <SectionButton label="HISTÓRIA" icon={BookOpen} colorClass="text-amber-400 bg-amber-900/20" onClick={() => setCurrentSection(NavSection.HISTORY)} />
               <SectionButton label="TREINOS" icon={MapPin} colorClass="text-green-400 bg-green-900/20" onClick={() => setCurrentSection(NavSection.LOCATIONS)} />
               <SectionButton label="AGENDA" icon={Calendar} colorClass="text-red-400 bg-red-900/20" onClick={() => setCurrentSection(NavSection.EVENTS)} />
               <SectionButton label="CHAT" icon={MessageCircle} colorClass="text-teal-400 bg-teal-900/20" onClick={() => setCurrentSection(NavSection.CHAT)} />
               <SectionButton label="LIVE" icon={Video} colorClass="text-pink-400 bg-pink-900/20" onClick={() => window.open(liveLink, '_blank')} />
               <SectionButton label="AI STUDIO" icon={Camera} colorClass="text-white bg-gradient-to-br from-brand-orange to-brand-red" onClick={() => setCurrentSection(NavSection.AI_STUDIO)} />
            </div>
         </div>
         <Footer />
      </div>
    );
  };

  return (
    <div className="min-h-screen font-sans bg-brand-dark text-white selection:bg-brand-red selection:text-white">
      <div className="max-w-md mx-auto bg-brand-dark min-h-screen shadow-2xl relative border-x border-gray-800">
        {renderContent()}
      </div>
    </div>
  );
}

