  const [nick, setNick] = useState('');
  const [pass, setPass] = useState('');

  return (
    <div className="bg-brand-card p-6 rounded-3xl shadow-2xl animate-fade-in-up border border-gray-700">
      <div className="flex items-center justify-between mb-6">
        <h2 className="font-suez text-xl text-white">{mode === 'ADMIN' ? 'ACESSO MESTRE' : 'ACESSO ALUNO'}</h2>
        <button onClick={onCancel} className="text-gray-400 hover:text-brand-red"><LogOut size={20} /></button>
      </div>

      <div className="space-y-5">
        <div>
          <label className="text-[10px] font-bold text-gray-500 uppercase tracking-widest block mb-1">Apelido (Obrigatório)</label>
          <input 
            type="text" 
            value={nick}
            onChange={(e) => setNick(e.target.value)}
