            placeholder="Seu apelido"
          />
        </div>
        <div>
          <label className="text-[10px] font-bold text-gray-500 uppercase tracking-widest block mb-1">Senha (Obrigatório)</label>
          <input 
            type="password" 
            value={pass}
            onChange={(e) => setPass(e.target.value)}
            className="w-full bg-brand-dark border-b-2 border-gray-700 py-2 focus:outline-none focus:border-brand-red font-bold text-lg text-white placeholder-gray-600 transition-colors"
            placeholder="••••••"
          />
        </div>

        <div className="pt-4">
          <FlameButton 
            label="SALVAR E ENTRAR" 
