import React, { useState, useRef } from 'react';
import { FlameButton } from './FlameButton';
import { chatWithGemini, transcribeAudio } from '../services/geminiService';
import { Send, Globe, Mic, Loader2, Bot, User as UserIcon } from 'lucide-react';

interface Message {
  id: string;
  role: 'user' | 'model';
  text: string;
  sources?: { title: string, uri: string }[];
}

export const AIChat: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([
    { id: '0', role: 'model', text: 'Salve! Sou o assistente virtual do Incendeia. Como posso ajudar hoje?' }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [useSearch, setUseSearch] = useState(false);
  const [isRecording, setIsRecording] = useState(false);

  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);

  const handleSend = async () => {
    if (!input.trim()) return;

    const userMsg: Message = { id: Date.now().toString(), role: 'user', text: input };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    try {
      // Prepare history for API
      const history = messages.map(m => ({
        role: m.role,
        parts: [{ text: m.text }]
      }));

      const { text, groundingUrls } = await chatWithGemini(history, userMsg.text, useSearch);

      const botMsg: Message = { 
        id: (Date.now() + 1).toString(), 
        role: 'model', 
        text,
        sources: groundingUrls
      };
      setMessages(prev => [...prev, botMsg]);
    } catch (error) {
      console.error(error);
      setMessages(prev => [...prev, { id: Date.now().toString(), role: 'model', text: 'Desculpe, tive um erro ao processar.' }]);
    } finally {
      setIsLoading(false);
    }
  };

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];

      mediaRecorder.ondataavailable = (event) => {
        audioChunksRef.current.push(event.data);
      };

      mediaRecorder.onstop = async () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/wav' });
        const reader = new FileReader();
        reader.readAsDataURL(audioBlob);
        reader.onloadend = async () => {
           const base64Audio = reader.result as string;
           setIsLoading(true);
           try {
             const text = await transcribeAudio(base64Audio);
             setInput(prev => prev + " " + text);
           } catch (e) {
             alert("Erro na transcrição");
           } finally {
             setIsLoading(false);
           }
        };
        stream.getTracks().forEach(track => track.stop());
      };

      mediaRecorder.start();
      setIsRecording(true);
    } catch (e) {
      console.error("Mic Error", e);
      alert("Erro ao acessar microfone");
    }
  };

  const stopRecording = () => {
    mediaRecorderRef.current?.stop();
    setIsRecording(false);
  };

  return (
    <div className="flex flex-col h-[75vh] bg-brand-card rounded-2xl overflow-hidden border border-gray-700 shadow-xl">
      {/* Header */}
      <div className="p-4 border-b border-gray-700 bg-brand-dark flex justify-between items-center">
        <h3 className="font-suez text-white flex items-center gap-2">
           <Bot className="text-brand-orange" /> Chat Inteligente
        </h3>
        <button 
          onClick={() => setUseSearch(!useSearch)}
          className={`flex items-center gap-1 px-3 py-1 rounded-full text-xs font-bold transition-colors ${useSearch ? 'bg-blue-600 text-white' : 'bg-gray-800 text-gray-400'}`}
        >
           <Globe size={12} /> Google Search {useSearch ? 'ON' : 'OFF'}
        </button>
      </div>

      {/* Messages */}
      <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-brand-dark/50">
        {messages.map(msg => (
          <div key={msg.id} className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
            <div className={`max-w-[85%] rounded-2xl p-3 text-sm ${
              msg.role === 'user' 
                ? 'bg-brand-red text-white rounded-tr-none' 
                : 'bg-gray-800 text-gray-100 rounded-tl-none border border-gray-700'
            }`}>
               {msg.text}
            </div>
            {msg.sources && msg.sources.length > 0 && (
               <div className="mt-2 text-[10px] text-gray-500 max-w-[85%]">
                  <strong className="block text-brand-orange mb-1">Fontes:</strong>
                  {msg.sources.map((s, i) => (
                    <a key={i} href={s.uri} target="_blank" rel="noreferrer" className="block truncate hover:text-blue-400 underline mb-1">
                      {s.title}
                    </a>
                  ))}
               </div>
            )}
          </div>
        ))}
        {isLoading && (
          <div className="flex items-center gap-2 text-gray-500 text-xs pl-2">
             <Loader2 className="animate-spin" size={14} /> Pensando...
          </div>
        )}
      </div>

      {/* Input */}
      <div className="p-3 bg-brand-card border-t border-gray-700 flex gap-2 items-end">
        <button 
           className={`p-3 rounded-full transition-all ${isRecording ? 'bg-red-600 animate-pulse' : 'bg-gray-700 text-gray-400 hover:text-white'}`}
           onClick={isRecording ? stopRecording : startRecording}
        >
           <Mic size={20} className={isRecording ? 'text-white' : ''} />
        </button>
        <textarea 
           value={input}
           onChange={(e) => setInput(e.target.value)}
           placeholder="Digite ou grave um áudio..."
           className="flex-1 bg-brand-dark border border-gray-700 rounded-xl px-4 py-3 text-sm text-white focus:outline-none focus:border-brand-orange resize-none h-12"
        />
        <button 
           onClick={handleSend}
           disabled={isLoading || !input.trim()}
           className="bg-brand-orange text-white p-3 rounded-xl disabled:opacity-50 disabled:cursor-not-allowed hover:bg-orange-600 transition-colors"
        >
           <Send size={20} />
        </button>
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { getLiveClient } from '../services/geminiService';
import { Modality, LiveServerMessage } from '@google/genai';
import { FlameButton } from './FlameButton';
import { Mic, MicOff, PhoneOff, Volume2, Activity } from 'lucide-react';

export const LiveSession: React.FC = () => {
  const [isConnected, setIsConnected] = useState(false);
  const [isMuted, setIsMuted] = useState(false);
  const [status, setStatus] = useState("Ready to connect");

  // Audio Context Refs
  const audioContextRef = useRef<AudioContext | null>(null);
  const inputSourceRef = useRef<MediaStreamAudioSourceNode | null>(null);
  const processorRef = useRef<ScriptProcessorNode | null>(null);
  const streamRef = useRef<MediaStream | null>(null);

  // Playback Refs
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

  // Connection Ref
  const sessionPromiseRef = useRef<Promise<any> | null>(null);

  const cleanup = () => {
    if (streamRef.current) {
        streamRef.current.getTracks().forEach(track => track.stop());
    }
    if (audioContextRef.current) {
        audioContextRef.current.close();
    }
    sessionPromiseRef.current = null;
    setIsConnected(false);
    setStatus("Disconnected");
  };

  // --- HELPERS FOR PCM ---
  function createBlob(data: Float32Array): { data: string, mimeType: string } {
    const l = data.length;
    const int16 = new Int16Array(l);
    for (let i = 0; i < l; i++) {
        int16[i] = data[i] * 32768;
    }
    // Simple encode to base64 for PCM
    let binary = '';
    const bytes = new Uint8Array(int16.buffer);
    const len = bytes.byteLength;
    for (let i = 0; i < len; i++) {
        binary += String.fromCharCode(bytes[i]);
    }
    const b64 = btoa(binary);

    return {
        data: b64,
        mimeType: 'audio/pcm;rate=16000',
    };
  }

  function decodeBase64(base64: string): Uint8Array {
      const binaryString = atob(base64);
      const len = binaryString.length;
      const bytes = new Uint8Array(len);
      for (let i = 0; i < len; i++) {
        bytes[i] = binaryString.charCodeAt(i);
      }
      return bytes;
  }

  async function decodeAudioData(
    data: Uint8Array,
    ctx: AudioContext,
    sampleRate: number = 24000,
    numChannels: number = 1
  ): Promise<AudioBuffer> {
      const dataInt16 = new Int16Array(data.buffer);
      const frameCount = dataInt16.length / numChannels;
      const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

      for (let channel = 0; channel < numChannels; channel++) {
        const channelData = buffer.getChannelData(channel);
        for (let i = 0; i < frameCount; i++) {
          channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
        }
      }
      return buffer;
  }

  const connect = async () => {
    setStatus("Initializing...");
    const ai = getLiveClient();

    try {
        // Init Audio Contexts
        audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
        const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });

        await audioContextRef.current.resume();

        // Get Mic
        const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
        streamRef.current = stream;

        // Establish Connection
        sessionPromiseRef.current = ai.live.connect({
            model: 'gemini-2.5-flash-native-audio-preview-12-2025',
            config: {
                responseModalities: [Modality.AUDIO],
                speechConfig: {
                    voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } }
                }
            },
            callbacks: {
                onopen: () => {
                    setStatus("Connected & Listening");
                    setIsConnected(true);

                    // Setup Input Processing
                    const source = inputCtx.createMediaStreamSource(stream);
                    const processor = inputCtx.createScriptProcessor(4096, 1, 1);

                    processor.onaudioprocess = (e) => {
                         if (isMuted) return;
                         const inputData = e.inputBuffer.getChannelData(0);
                         const pcmBlob = createBlob(inputData);
                         sessionPromiseRef.current?.then((session: any) => {
                             session.sendRealtimeInput({ media: pcmBlob });
                         });
                    };

                    source.connect(processor);
                    processor.connect(inputCtx.destination);

                    inputSourceRef.current = source;
                    processorRef.current = processor;
                },
                onmessage: async (msg: LiveServerMessage) => {
                    // Handle Output
                    const base64Audio = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
                    if (base64Audio && audioContextRef.current) {
                        const bytes = decodeBase64(base64Audio);
                        const buffer = await decodeAudioData(bytes, audioContextRef.current);

                        nextStartTimeRef.current = Math.max(nextStartTimeRef.current, audioContextRef.current.currentTime);

                        const source = audioContextRef.current.createBufferSource();
                        source.buffer = buffer;
                        source.connect(audioContextRef.current.destination);

                        source.addEventListener('ended', () => {
                           sourcesRef.current.delete(source);
                        });

                        source.start(nextStartTimeRef.current);
                        nextStartTimeRef.current += buffer.duration;
                        sourcesRef.current.add(source);
                    }

                    if (msg.serverContent?.interrupted) {
                        sourcesRef.current.forEach(s => s.stop());
                        sourcesRef.current.clear();
                        nextStartTimeRef.current = 0;
                    }
                },
                onclose: () => cleanup(),
                onerror: (e) => {
                    console.error(e);
                    setStatus("Error occurred");
                    cleanup();
                }
            }
        });

    } catch (e) {
        console.error("Connection failed", e);
        setStatus("Failed to connect");
    }
  };

  return (
    <div className="flex flex-col items-center justify-center h-[60vh] bg-brand-card rounded-3xl border border-gray-700 shadow-2xl relative overflow-hidden">
        {/* Background Animation */}
        <div className={`absolute inset-0 transition-opacity duration-1000 ${isConnected ? 'opacity-20' : 'opacity-0'}`}>
             <div className="absolute inset-0 bg-gradient-to-t from-red-900 to-transparent animate-pulse" />
        </div>

        <div className="z-10 flex flex-col items-center gap-6">
            <div className={`w-32 h-32 rounded-full border-4 flex items-center justify-center shadow-[0_0_30px_rgba(251,133,0,0.3)] transition-all duration-500 ${isConnected ? 'border-brand-orange scale-110' : 'border-gray-700'}`}>
                {isConnected ? (
                    <Activity size={48} className="text-brand-orange animate-bounce" />
                ) : (
                    <Volume2 size={48} className="text-gray-600" />
                )}
            </div>

            <div className="text-center">
                <h3 className="font-suez text-2xl text-white">Live Voice</h3>
                <p className="text-sm text-gray-400 font-mono mt-2 uppercase tracking-widest">{status}</p>
            </div>

            <div className="flex gap-4 mt-4">
                {!isConnected ? (
                    <FlameButton label="START CALL" onClick={connect} />
                ) : (
                    <>
                        <button 
                          onClick={() => setIsMuted(!isMuted)}
                          className={`p-4 rounded-full border-2 transition-all ${isMuted ? 'bg-red-900/50 border-red-500 text-red-500' : 'bg-gray-800 border-gray-600 text-white'}`}
                        >
                           {isMuted ? <MicOff size={24} /> : <Mic size={24} />}
                        </button>
                        <button 
                          onClick={cleanup}
                          className="p-4 rounded-full bg-red-600 text-white hover:bg-red-700 shadow-lg"
                        >
                           <PhoneOff size={24} />
                        </button>
                    </>
                )}
            </div>
        </div>
    </div>
  );
};

