import React from 'react';
import { Flame } from 'lucide-react';

interface FlameButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  label: string;
  variant?: 'primary' | 'secondary' | 'danger';
  iconSize?: number;
}

export const FlameButton: React.FC<FlameButtonProps> = ({ 
  label, 
  variant = 'primary', 
  iconSize = 14,
  className = '',
  ...props 
}) => {
  // Base: Rounded-full, Flex, Shadow
  // Updates: Reduced padding (px-4 py-2) and text size (text-xs)
  let baseClasses = "flex items-center justify-center gap-2 rounded-full px-4 py-2 font-suez text-xs transition-all active:scale-95 shadow-lg border-2";

  const variants = {
    // Primary: Red background, Red-Dark Border, White Text
    primary: "bg-brand-red border-red-800 text-white hover:bg-red-700 hover:shadow-orange-500/20",
    // Secondary: Dark Card background, Gray Border, White Text
    secondary: "bg-brand-card border-gray-700 text-white hover:bg-gray-800",
    // Danger: Black/Darker Red
    danger: "bg-black text-red-500 border-red-900 hover:bg-gray-900"
  };

  return (
    <button 
      className={`${baseClasses} ${variants[variant]} ${className}`}
      {...props}
    >
      <div className="bg-white/10 p-1 rounded-full">
        <Flame size={iconSize} className="text-brand-orange fill-brand-orange" />
      </div>
      <span className="tracking-wide">{label}</span>
    </button>
  );
};

import React from 'react';
