interface BottomNavProps {
  currentSection: NavSection;
  onNavigate: (section: NavSection) => void;
}

export const BottomNav: React.FC<BottomNavProps> = ({ currentSection, onNavigate }) => {
  const navItems = [
    { section: NavSection.HOME, icon: Home, label: 'Home' },
    { section: NavSection.PROFILE, icon: User, label: 'Perfil' },
    { section: NavSection.CHAT, icon: MessageCircle, label: 'Chat' },
    { section: NavSection.GALLERY, icon: ImageIcon, label: 'Galeria' },
    { section: NavSection.EVENTS, icon: Calendar, label: 'Eventos' },
  ];

  return (
    <div className="fixed bottom-0 w-full max-w-md mx-auto bg-brand-card border-t border-gray-800 pb-safe pt-2 px-2 z-50 flex justify-between items-center shadow-2xl">
      {navItems.map((item) => {
        const isActive = currentSection === item.section;
        return (
          <button
            key={item.label}
            onClick={() => onNavigate(item.section)}
            className={`relative flex flex-col items-center justify-center p-2 w-1/5 transition-all duration-300 ${isActive ? '-translate-y-2' : ''}`}
          >
            {/* Fireball Effect Background for Active State */}
            {isActive && (
              <div className="absolute inset-0 bg-gradient-to-t from-brand-red to-brand-orange rounded-full blur-md opacity-60 scale-75 animate-pulse"></div>
            )}

            {/* Icon Container */}
            <div className={`relative z-10 p-2 rounded-full transition-colors ${
              isActive 
                ? 'bg-brand-dark border-2 border-brand-orange text-brand-orange shadow-[0_0_15px_rgba(251,133,0,0.6)]' 
                : 'text-gray-500'
            }`}>
              <item.icon size={isActive ? 20 : 18} strokeWidth={isActive ? 2.5 : 2} />
            </div>

            {/* Label */}
            <span className={`text-[9px] font-bold mt-1 transition-colors z-10 ${isActive ? 'text-brand-orange' : 'text-gray-600'}`}>
              {item.label}
            </span>
          </button>
        );
      })}
    </div>
  );
};

