// --- MAIN APP ---

export default function App() {
  // --- STATE ---
  const [user, setUser] = useState<User | null>(null);
  const [lang, setLang] = useState<Language>(Language.PT);
  const [currentSection, setCurrentSection] = useState<NavSection>(NavSection.HOME);
  const [loginMode, setLoginMode] = useState<'MEMBER' | 'ADMIN' | null>(null);

  // --- DATABASE STATE (Simulating Backend) ---
  const [masters, setMasters] = useState<Master[]>(INITIAL_MASTERS);
  const [locations, setLocations] = useState<TrainingLocation[]>(INITIAL_LOCATIONS);
  const [chatMessages, setChatMessages] = useState<ChatMessage[]>([]);
  const [members, setMembers] = useState<User[]>([]); 
  const [galleryItems, setGalleryItems] = useState<GalleryItem[]>([]);
  const [liveLink, setLiveLink] = useState("https://meet.google.com");

  // --- LAYOUT EDITOR STATE ---
  const [layoutConfig, setLayoutConfig] = useState({
    themeColor: '#121212',
    buttonColor: '#D90429',
    fontSize: 16,
    lineSpacing: 1.5,
    letterSpacing: 0.5
  });

  // --- ADMIN STATE ---
  const [adminCount, setAdminCount] = useState(0);

  // --- ACTIONS ---

  const handleLogin = (role: UserRole, nickname: string, pass: string) => {
    if (!nickname || !pass) return alert("Preencha todos os campos!");

    if (role === UserRole.ADMIN) {
      if (adminCount >= 2) {
         // Logic for limiting admins
      }
      setAdminCount(prev => prev + 1);
    }

    const newUser: User = {
      id: Date.now().toString(),
      nickname,
      name: nickname, // Default
      role,
      graduation: role === UserRole.MEMBER ? 'Iniciante' : 'Mestre',
      graduationColor: role === UserRole.MEMBER ? '#22c55e' : '#FFFFFF',
      since: '1 mês'
    };

    setMembers(prev => [...prev, newUser]);
    setUser(newUser);
    setCurrentSection(NavSection.HOME);
    setLoginMode(null);
  };

  const handleLogout = () => {
    setUser(null);
    setCurrentSection(NavSection.HOME);
    setLoginMode(null);
  };

  const goHome = () => setCurrentSection(NavSection.HOME);

  // --- HELPER: MEDIA UPLOAD ---
  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, callback: (url: string, type: 'image'|'video') => void) => {
      const file = e.target.files?.[0];
      if (file) {
          const type = file.type.startsWith('video') ? 'video' : 'image';
          const reader = new FileReader();
          reader.onloadend = () => {
              callback(reader.result as string, type);
          };
          reader.readAsDataURL(file);
      }
  };

  const handleGalleryUpload = (url: string, type: 'image'|'video') => {
    if (!user) return;
    const newItem: GalleryItem = {
      id: Date.now().toString(),
      type,
      url,
      likes: [],
      comments: [],
      uploadedBy: user.id,
      timestamp: Date.now()
    };
    setGalleryItems(prev => [newItem, ...prev]);
  };

  const handleLike = (itemId: string) => {
    if (!user) return;
    setGalleryItems(prev => prev.map(item => {
      if (item.id === itemId) {
        const hasLiked = item.likes.includes(user.id);
        return {
          ...item,
          likes: hasLiked ? item.likes.filter(id => id !== user.id) : [...item.likes, user.id]
        };
      }
      return item;
    }));
  };

  const handleComment = (itemId: string, text: string) => {
    if (!user || !text.trim()) return;
    setGalleryItems(prev => prev.map(item => {
      if (item.id === itemId) {
        const newComment: Comment = {
           id: Date.now().toString(),
           userId: user.id,
           nickname: user.nickname,
           text,
           timestamp: Date.now()
        };
        return { ...item, comments: [...item.comments, newComment] };
      }
      return item;
    }));
  };

  const deleteGalleryItem = (id: string) => {
    setGalleryItems(prev => prev.filter(i => i.id !== id));
  };

  // --- RENDERERS ---

  // 1. LOGIN SCREEN
  if (!user) {
    return (
      <div className="min-h-screen bg-brand-dark flex flex-col items-center justify-center relative overflow-hidden p-4">
        {/* Language Selector */}
        <div className="absolute top-8 flex gap-4 z-20 bg-brand-card/50 p-2 rounded-full backdrop-blur-md border border-gray-700">
           <button onClick={() => setLang(Language.PT)} className={`transition-all hover:scale-110 ${lang === Language.PT ? 'opacity-100 grayscale-0' : 'opacity-40 grayscale'}`}>
             <span className="text-2xl drop-shadow-md">🇧🇷</span>
           </button>
           <button onClick={() => setLang(Language.ES)} className={`transition-all hover:scale-110 ${lang === Language.ES ? 'opacity-100 grayscale-0' : 'opacity-40 grayscale'}`}>
             <span className="text-2xl drop-shadow-md">🇪🇸</span>
           </button>
        </div>

        {/* LOGO */}
        <div className="mb-8 flex flex-col items-center z-10 w-full">
            <div className="w-48 h-48 rounded-full shadow-2xl flex items-center justify-center mb-6 border-4 border-brand-card bg-black overflow-hidden relative group">
               <img 
                 src="https://i.ibb.co/V0WppRbR/1770855196310.png" 
                 alt="Incendeia Capoeira Logo" 
                 className="w-full h-full object-cover transform transition-transform group-hover:scale-105"
               />
            </div>

            {/* TEXTO COM EFEITO */}
            <h1 className="text-4xl md:text-5xl font-suez text-center leading-tight tracking-tight drop-shadow-lg flex flex-col gap-1">
              <span className="text-brazil block">
                INCENDEIA
              </span>
              <span className="text-spain block">
                CAPOEIRA
              </span>
            </h1>
        </div>

        {/* BUTTONS AREA */}
        <div className="w-full max-w-sm space-y-4 z-10 mb-12">
          {!loginMode ? (
            <>
              <button 
                onClick={() => setLoginMode('MEMBER')}
                className="w-full bg-brand-card border border-gray-700 p-4 rounded-3xl shadow-lg flex items-center justify-between hover:border-brand-red transition-all active:scale-95 group"
              >
                <div className="flex items-center gap-4">
                  <div className="bg-brand-red p-3 rounded-full text-white shadow-lg shadow-red-900/50"><Users size={24}/></div>
                  <div className="text-left">
                    <span className="block font-suez text-white text-lg tracking-wide group-hover:text-brand-orange transition-colors">MEMBROS</span>
                    <span className="text-xs text-gray-400 font-bold">LOGIN / CADASTRO</span>
                  </div>
                </div>
              </button>

              <button 
                onClick={() => setLoginMode('ADMIN')}
                className="w-full bg-brand-card border border-gray-700 p-4 rounded-3xl shadow-lg flex items-center justify-between hover:border-brand-red transition-all active:scale-95 group"
              >
                <div className="flex items-center gap-4">
                  <div className="bg-gray-700 p-3 rounded-full text-white"><Shield size={24}/></div>
                  <div className="text-left">
                    <span className="block font-suez text-white text-lg tracking-wide group-hover:text-brand-orange transition-colors">ADM</span>
                    <span className="text-xs text-gray-400 font-bold">MESTRES (MAX 2)</span>
                  </div>
                </div>
              </button>
            </>
          ) : (
             <LoginForm 
                mode={loginMode} 
                onCancel={() => setLoginMode(null)} 
                onSubmit={(nick, pass) => handleLogin(loginMode === 'ADMIN' ? UserRole.ADMIN : UserRole.MEMBER, nick, pass)}
             />
          )}
        </div>

        <Footer />
      </div>
    );
  }

  // --- INTERNAL NAVIGATOR ---

  const renderContent = () => {
    // 2. ADMIN PANEL
    if (currentSection === NavSection.ADMIN_PANEL) {
       return (
         <PageLayout title="PAINEL ADMINISTRATIVO" onBack={goHome} onLogout={handleLogout} showBottomNav={true} currentSection={currentSection} onNavigate={setCurrentSection}>
            <div className="space-y-6">
              <div className="bg-brand-card p-5 rounded-2xl shadow-lg border border-gray-700">
                <h3 className="font-suez text-white mb-4 flex items-center gap-2 border-b border-gray-700 pb-2"><PenTool size={18} className="text-brand-orange"/> GERENCIAR CONTEÚDO</h3>
                <div className="grid grid-cols-2 gap-3">
                   {/* Admin Buttons Grid */}
                   <AdminMenuButton label="Layout" icon={PenTool} onClick={() => setCurrentSection(NavSection.LAYOUT_EDITOR)} />
                   <AdminMenuButton label="Mestres" icon={Users} onClick={() => setCurrentSection(NavSection.MASTERS)} />
                   <AdminMenuButton label="Galeria" icon={ImageIcon} onClick={() => setCurrentSection(NavSection.GALLERY)} />
                   <AdminMenuButton label="Graduação" icon={Map} onClick={() => alert("Editor de Sistema de Graduação")} />
                   <AdminMenuButton label="Histórico" icon={BookOpen} onClick={() => setCurrentSection(NavSection.HISTORY)} />
                   <AdminMenuButton label="Locais" icon={MapPin} onClick={() => setCurrentSection(NavSection.LOCATIONS)} />
                   <AdminMenuButton label="Agenda" icon={Calendar} onClick={() => setCurrentSection(NavSection.EVENTS)} />
                   <AdminMenuButton label="Live Link" icon={Video} onClick={() => {
                      const newLink = prompt("Insira o novo link da Live (Zoom/Meet/WhatsApp):", liveLink);
                      if(newLink) setLiveLink(newLink);
                   }} />
                </div>
              </div>

              <div className="bg-gradient-to-br from-red-900/20 to-black p-5 rounded-2xl border border-red-900/50">
                <h3 className="font-suez text-brand-red mb-2 flex items-center gap-2"><Shield size={18}/> SALA DE MESTRES</h3>
                <p className="text-xs text-gray-400 mb-4">Área privada criptografada para reunião entre os 2 ADMs.</p>
                <FlameButton label="ENTRAR NA SALA" variant="primary" className="w-full" onClick={() => setCurrentSection(NavSection.MEETING_ROOM)} />
              </div>
            </div>
         </PageLayout>
       );
    }

    // 3. GALLERY (UPDATED FOR UPLOAD AND INTERACTIONS)
    if (currentSection === NavSection.GALLERY) {
        return (
            <PageLayout title="GALERIA DO GRUPO" onBack={goHome} onLogout={handleLogout} showBottomNav={true} currentSection={currentSection} onNavigate={setCurrentSection}>
                {/* Admin Upload Section */}
                {user.role === UserRole.ADMIN && (
                    <div className="mb-6 bg-brand-card p-4 rounded-xl shadow-lg border border-gray-700">
                        <label className="flex flex-col items-center justify-center border-2 border-dashed border-gray-600 rounded-xl p-6 cursor-pointer hover:bg-gray-800 transition-colors">
                            <Upload size={32} className="text-brand-orange mb-2" />
                            <span className="font-suez text-xs text-white uppercase">Carregar Foto ou Vídeo</span>
                            <span className="text-[9px] text-gray-500 mt-1">Do armazenamento interno</span>
                            <input 
                                type="file" 
                                className="hidden" 
                                accept="image/*,video/*"
                                onChange={(e) => handleFileUpload(e, handleGalleryUpload)}
                            />
                        </label>
                    </div>
                )}

                {/* Gallery Grid */}
                <div className="space-y-6">
                    {galleryItems.length === 0 && (
                        <div className="text-center py-10 text-gray-500">
                            <ImageIcon size={48} className="mx-auto mb-2 opacity-20" />
                            <p className="text-xs">A galeria está vazia.</p>
                        </div>
                    )}

                    {galleryItems.map(item => (
                        <div key={item.id} className="bg-brand-card rounded-2xl overflow-hidden shadow-lg border border-gray-800">
                            {/* Media Display */}
                            <div className="w-full bg-black flex items-center justify-center min-h-[200px]">
                                {item.type === 'image' ? (
                                    <img src={item.url} alt="Gallery" className="w-full h-auto max-h-[400px] object-contain" />
                                ) : (
                                    <video src={item.url} controls className="w-full h-auto max-h-[400px]" />
                                )}
                            </div>

                            {/* Actions Bar */}
                            <div className="p-3 flex items-center justify-between border-b border-gray-800">
                                <div className="flex gap-4">
                                    <button 
                                        onClick={() => handleLike(item.id)}
                                        className={`flex items-center gap-1 text-xs font-bold transition-colors ${item.likes.includes(user.id) ? 'text-brand-red' : 'text-gray-400 hover:text-white'}`}
                                    >
                                        <Heart size={18} fill={item.likes.includes(user.id) ? "currentColor" : "none"} />
                                        {item.likes.length}
                                    </button>
                                    <button className="flex items-center gap-1 text-xs font-bold text-gray-400">
                                        <CommentIcon size={18} />
                                        {item.comments.length}
                                    </button>
                                </div>
                                {user.role === UserRole.ADMIN && (
                                    <button onClick={() => deleteGalleryItem(item.id)} className="text-red-900 hover:text-red-500">
                                        <Trash2 size={16} />
                                    </button>
                                )}
                            </div>

                            {/* Comments Section */}
                            <div className="p-3 bg-brand-dark/30">
                                <div className="space-y-2 mb-3 max-h-32 overflow-y-auto">
                                    {item.comments.map(c => (
                                        <div key={c.id} className="text-xs">
                                            <span className="font-bold text-brand-orange mr-1">{c.nickname}:</span>
                                            <span className="text-gray-300">{c.text}</span>
                                        </div>
                                    ))}
                                </div>
                                <div className="flex gap-2">
                                    <input 
                                        type="text" 
                                        placeholder="Comente algo..." 
                                        className="flex-1 bg-brand-dark border border-gray-700 rounded-full px-3 py-1 text-xs text-white focus:outline-none focus:border-brand-orange"
                                        onKeyDown={(e) => {
                                            if (e.key === 'Enter') {
                                                handleComment(item.id, (e.target as HTMLInputElement).value);
                                                (e.target as HTMLInputElement).value = '';
                                            }
                                        }}
                                        id={`comment-input-${item.id}`}
                                    />
                                    <button 
                                        onClick={() => {
                                            const input = document.getElementById(`comment-input-${item.id}`) as HTMLInputElement;
                                            handleComment(item.id, input.value);
                                            input.value = '';
                                        }}
                                        className="text-brand-orange hover:text-white"
                                    >
                                        <Send size={16} />
                                    </button>
                                </div>
                            </div>
                        </div>
                    ))}
                </div>
            </PageLayout>
        );
    }

    // For other sections, we wrap them in PageLayout with BottomNav where appropriate
    const showNav = [NavSection.HOME, NavSection.PROFILE, NavSection.CHAT, NavSection.GALLERY, NavSection.EVENTS].includes(currentSection);

    // 8. AI STUDIO
    if (currentSection === NavSection.AI_STUDIO) {
        return (
            <PageLayout title="AI STUDIO" onBack={goHome} onLogout={handleLogout} showBottomNav={showNav} currentSection={currentSection} onNavigate={setCurrentSection}>
                <GeminiStudio />
            </PageLayout>
        );
    }

    // 9. AI CHAT
    if (currentSection === NavSection.AI_CHAT) {
        return (
            <PageLayout title="ASSISTENTE IA" onBack={goHome} onLogout={handleLogout} showBottomNav={showNav} currentSection={currentSection} onNavigate={setCurrentSection}>
                <AIChat />
            </PageLayout>
        );
    }

    // 10. LIVE SESSION
    if (currentSection === NavSection.LIVE_SESSION) {
        return (
            <PageLayout title="LIVE VOICE" onBack={goHome} onLogout={handleLogout} showBottomNav={showNav} currentSection={currentSection} onNavigate={setCurrentSection}>
                <LiveSession />
            </PageLayout>
        );
    }

    // DEFAULT: HOME MENU (USER DASHBOARD)
    // We update this to respect the new Bottom Nav logic, but keep the dashboard buttons as quick actions
    if (currentSection === NavSection.HOME) {
        return (
          <PageLayout title="INCENDEIA" onLogout={handleLogout} showBottomNav={true} currentSection={currentSection} onNavigate={setCurrentSection}>
             <div className="space-y-6">
                {/* WELCOME */}
                <div className="bg-brand-card p-6 rounded-3xl shadow-lg border border-gray-800 relative overflow-hidden">
                   <div className="flex items-center justify-between relative z-10">
                       <div>
                           <h2 className="text-xl font-suez text-white mb-1">Olá, {user.nickname}!</h2>
                           <p className="text-xs text-gray-400">Bem-vindo(a) de volta.</p>
                       </div>
                       <div className="w-12 h-12 rounded-full border-2 border-brand-orange bg-brand-dark overflow-hidden">
                            {user.avatar ? <img src={user.avatar} className="w-full h-full object-cover"/> : <Users className="w-full h-full p-2 text-gray-500"/>}
                       </div>
                   </div>
                </div>

                {/* DASHBOARD GRID - Keep existing buttons but organize them */}
                <div className="grid grid-cols-3 gap-3">
                   {/* Only visible to Admin */}
                   {user.role === UserRole.ADMIN && (
                     <div className="col-span-3">
                        <SectionButton label="PAINEL ADM" icon={Shield} colorClass="text-brand-red bg-white" onClick={() => setCurrentSection(NavSection.ADMIN_PANEL)} />
                     </div>
                   )}

                   <SectionButton label="MURAL" icon={Globe} colorClass="text-indigo-400 bg-indigo-900/20" onClick={() => setCurrentSection(NavSection.MEMBERS_WALL)} />
                   <SectionButton label="AI CHAT" icon={Bot} colorClass="text-emerald-400 bg-emerald-900/20" onClick={() => setCurrentSection(NavSection.AI_CHAT)} />
                   <SectionButton label="LIVE" icon={Mic2} colorClass="text-rose-400 bg-rose-900/20" onClick={() => setCurrentSection(NavSection.LIVE_SESSION)} />

                   <SectionButton label="STUDIO" icon={Sparkles} colorClass="text-white bg-gradient-to-br from-brand-orange to-brand-red" onClick={() => setCurrentSection(NavSection.AI_STUDIO)} />
                   <SectionButton label="HISTÓRIA" icon={BookOpen} colorClass="text-amber-400 bg-amber-900/20" onClick={() => setCurrentSection(NavSection.HISTORY)} />
                   <SectionButton label="TREINOS" icon={MapPin} colorClass="text-green-400 bg-green-900/20" onClick={() => setCurrentSection(NavSection.LOCATIONS)} />
                </div>
             </div>
          </PageLayout>
        );
    }

    // Fallback for other sections
    return (
        <PageLayout title={currentSection} onBack={goHome} onLogout={handleLogout} showBottomNav={showNav} currentSection={currentSection} onNavigate={setCurrentSection}>
             <div className="flex flex-col items-center justify-center h-64 text-gray-500">
                 <p>Seção em desenvolvimento...</p>
                 {user.role === UserRole.ADMIN && <FlameButton label="ADICIONAR CONTEÚDO" variant="secondary" className="mt-4" />}
            </div>
        </PageLayout>
    );
  };

  return (
    <div className="min-h-screen font-sans bg-brand-dark text-white selection:bg-brand-red selection:text-white">
      <div className="max-w-md mx-auto bg-brand-dark min-h-screen shadow-2xl relative border-x border-gray-800">
        {renderContent()}
      </div>
    </div>
  );
}

